3	import (
4		"errors"
5		"fmt"
6		"net"
7		"net/url"
8		"regexp"
9		"strconv"
10		"strings"
11	
12		"k8s.io/apimachinery/pkg/util/validation"
13	)
14	
15	const (
16		// Regex from: https://github.com/kubernetes-sigs/gateway-api/blob/v1.4.1/apis/v1/shared_types.go#L675
17		controllerNameRegex = `^[a-z0-9]([-a-z0-9]*[a-z0-9])?(\.[a-z0-9]([-a-z0-9]*[a-z0-9])?)*\/[A-Za-z0-9\/\-._~%!$&'()*+,;=:]+$` //nolint:lll
18	)
19	
20	func validateGatewayControllerName(value string) error {
21		if len(value) == 0 {
22			return errors.New("must be set")
23		}
24	
25		fields := strings.Split(value, "/")
26		l := len(fields)
27		if l < 2 {
28			return errors.New("invalid format; must be DOMAIN/PATH")
29		}
30	
31		if fields[0] != domain {
32			return fmt.Errorf("invalid domain: %s; domain must be: %s", fields[0], domain)
33		}
34	
35		re := regexp.MustCompile(controllerNameRegex)
36		if !re.MatchString(value) {
37			return fmt.Errorf("invalid gateway controller name: %s; expected format is DOMAIN/PATH", value)
38		}
39	
40		return nil
41	}
42	
43	func validateResourceName(value string) error {
44		if len(value) == 0 {
45			return errors.New("must be set")
46		}
47	
48		// used by Kubernetes to validate resource names
49		messages := validation.IsDNS1123Subdomain(value)
50		if len(messages) > 0 {
51			msg := strings.Join(messages, "; ")
52			return fmt.Errorf("invalid format: %s", msg)
53		}
54	
55		return nil
56	}
57	
58	// validateNamespacedResourceName validates a resource name that may optionally be prefixed with a namespace
59	// in the format "namespace/name". Both the namespace and name portions must be valid DNS1123 subdomains.
60	// If no "/" is present, the entire value is validated as a plain resource name.
61	func validateNamespacedResourceName(value string) error {
62		if len(value) == 0 {
63			return errors.New("must be set")
64		}
65	
66		parts := strings.Split(value, "/")
67		switch len(parts) {
68		case 1:
69			return validateResourceName(value)
70		case 2:
71			if msgs := validation.IsDNS1123Subdomain(parts[0]); len(msgs) > 0 {
72				return fmt.Errorf("invalid namespace: %s", strings.Join(msgs, "; "))
73			}
74			if msgs := validation.IsDNS1123Subdomain(parts[1]); len(msgs) > 0 {
75				return fmt.Errorf("invalid name: %s", strings.Join(msgs, "; "))
76			}
77			return nil
78		default:
79			return fmt.Errorf("invalid format: expected name or namespace/name, got %q", value)
80		}
81	}
82	
83	func validateQualifiedName(name string) error {
84		if len(name) == 0 {
85			return errors.New("must be set")
86		}
87	
88		messages := validation.IsQualifiedName(name)
89		if len(messages) > 0 {
90			msg := strings.Join(messages, "; ")
91			return fmt.Errorf("invalid format: %s", msg)
92		}
93	
94		return nil
95	}
96	
97	func validateIP(ip string) error {
98		if ip == "" {
99			return errors.New("IP address must be set")
100		}
101		if net.ParseIP(ip) == nil {
102			return fmt.Errorf("%q must be a valid IP address", ip)
103		}
104	
105		return nil
106	}
107	
108	// validateEndpoint validates an endpoint, which is <host>:<port> where host is either a hostname or an IP address.
109	func validateEndpoint(endpoint string) error {
110		host, port, err := net.SplitHostPort(endpoint)
111		if err != nil {
112			return fmt.Errorf("%q must be in the format <host>:<port>: %w", endpoint, err)
113		}
114	
115		portVal, err := strconv.ParseInt(port, 10, 16)
116		if err != nil {
117			return fmt.Errorf("port must be a valid number: %w", err)
118		}
119	
120		if portVal < 1 || portVal > 65535 {
121			return fmt.Errorf("port outside of valid port range [1 - 65535]: %v", port)
122		}
123	
124		if err := validateIP(host); err == nil {
125			return nil
126		}
127	
128		if errs := validation.IsDNS1123Subdomain(host); len(errs) == 0 {
129			return nil
130		}
131	
132		// we don't know if the user intended to use a hostname or an IP address,
133		// so we return a generic error message
134		return fmt.Errorf("%q must be in the format <host>:<port>", endpoint)
135	}
136	
137	func validateEndpointOptionalPort(value string) error {
138		if len(value) == 0 {
139			return errors.New("must be set")
140		}
141	
142		host, port, err := splitHostPort(value)
143		if err != nil {
144			return err
145		}
146	
147		if port != "" {
148			if err := validatePortString(port); err != nil {
149				return err
150			}
151		}
152	
153		if err := validateIP(host); err == nil {
154			return nil
155		}
156	
157		if errs := validation.IsDNS1123Subdomain(host); len(errs) == 0 {
158			return nil
159		}
160	
161		// we don't know if the user intended to use a hostname or an IP address,
162		// so we return a generic error message
163		return fmt.Errorf("%q must be in the format [http://|https://]<host>[:<port>]", value)
164	}
165	
166	// splitHostPort extracts the host and optional port from an endpoint value that may include an http/https scheme.
167	// It uses net/url for scheme-prefixed values to correctly handle bracketed IPv6 addresses.
168	func splitHostPort(value string) (host, port string, err error) {
169		if strings.Contains(value, "://") {
170			u, parseErr := url.Parse(value)
171			if parseErr != nil {
172				return "", "", fmt.Errorf("invalid URL %q: %w", value, parseErr)
173			}
174			if u.Scheme != "http" && u.Scheme != "https" {
175				return "", "", fmt.Errorf("unsupported scheme %q: must be http or https", u.Scheme)
176			}
177			if u.Path != "" && u.Path != "/" {
178				return "", "", fmt.Errorf("invalid URL %q: path is not allowed", value)
179			}
180			if u.RawQuery != "" {
181				return "", "", fmt.Errorf("invalid URL %q: query is not allowed", value)
182			}
183			if u.Fragment != "" {
184				return "", "", fmt.Errorf("invalid URL %q: fragment is not allowed", value)
185			}
186			return u.Hostname(), u.Port(), nil
187		}
188	
189		// net.SplitHostPort requires a port; when the value has no port, it returns a "missing port" error.
190		// We treat that as valid (port is optional) and return the original value as host.
191		host, port, splitErr := net.SplitHostPort(value)
192		if splitErr != nil {
193			if strings.Contains(splitErr.Error(), "missing port") || strings.Contains(splitErr.Error(), "too many colons") {
194				return value, "", nil
195			}
196			return "", "", fmt.Errorf("error splitting %q into host and port: %w", value, splitErr)
197		}
198	
199		return host, port, nil
200	}
201	
202	func validatePortString(port string) error {
203		portVal, err := strconv.ParseInt(port, 10, 16)
204		if err != nil {
205			return fmt.Errorf("port must be a valid number: %w", err)
206		}
207		if portVal < 1 || portVal > 65535 {
208			return fmt.Errorf("port outside of valid port range [1 - 65535]: %v", port)
209		}
210		return nil
211	}
212	
213	func validateURL(value string) error {
214		if len(value) == 0 {
215			return errors.New("must be set")
216		}
217	
218		parsedURL, err := url.ParseRequestURI(value)
219		if err != nil {
220			return fmt.Errorf("invalid URL: %w", err)
221		}
222	
223		if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
224			return fmt.Errorf("unsupported URL scheme %q: must be http or https", parsedURL.Scheme)
225		}
226	
227		if parsedURL.Host == "" {
228			return errors.New("URL host must be set")
229		}
230	
231		return nil
232	}
233	
234	// validatePort makes sure a given port is inside the valid port range for its usage.
235	func validatePort(port int) error {
236		if port < 1024 || port > 65535 {
237			return fmt.Errorf("port outside of valid port range [1024 - 65535]: %v", port)
238		}
239		return nil
240	}
241	
242	// validateAnyPort makes sure a given port is inside the valid range for all ports.
243	// This includes protected ports (1-1023) and unprivileged ports (1024-65535).
244	func validateAnyPort(port int) error {
245		if port < 1 || port > 65535 {
246			return fmt.Errorf("port outside of valid port range [1 - 65535]: %v", port)
247		}
248		return nil
249	}
250	
251	// ensureNoPortCollisions checks if the same port has been defined multiple times.
252	func ensureNoPortCollisions(ports ...int) error {
253		seen := make(map[int]struct{})
254	
255		for _, port := range ports {
256			if _, ok := seen[port]; ok {
257				return fmt.Errorf("port %d has been defined multiple times", port)
258			}
259			seen[port] = struct{}{}
260		}
261	
262		return nil
263	}
